questoes:[{"enunciado": "A obra \"Casa-Grande & Senzala\", de Gilberto Freyre (1933), teve papel central na construção de qual ideia sobre o Brasil?", "alternativas": ["A ideia de racismo institucional evidente", "O mito da \"democracia racial\"", "A necessidade urgente de reparação histórica", "A separação racial legal, como nos EUA"], "correta": 1, "comentario": "Freyre defendia uma miscigenação supostamente"}, {"enunciado": "O \"mito da democracia racial\" teve como efeito político principal:", "alternativas": ["Fortalecer políticas de combate ao racismo", "Desqualificar demandas por políticas de reparação, ao negar a", "Promover imediatamente a igualdade racial", "Criar leis de segregação racial"], "correta": 1, "comentario": "Ao afirmar que \"não havia racismo\", o mito"}, {"enunciado": "Os estudos da UNESCO sobre relações raciais no Brasil, realizados nos anos 1950, tiveram como resultado:", "alternativas": ["Confirmar que o Brasil era, de fato, uma democracia racial", "Evidenciar a existência de forte discriminação racial no país", "Provar que não havia diferenças entre brancos e negros", "Recomendar o fim de qualquer pesquisa racial no Brasil"], "correta": 1, "comentario": "Contrariando a expectativa inicial, os estudos"}, {"enunciado": "O conceito de \"racismo estrutural\", que passou a ganhar força na desconstrução do mito da democracia racial, refere-se a:", "alternativas": ["Racismo restrito a atitudes individuais isoladas", "Um racismo embutido nas instituições e no funcionamento da sociedade", "A ausência total de racismo no Brasil", "Um fenômeno exclusivo de outros países"], "correta": 1, "comentario": "O racismo estrutural vai além de atitudes"}, {"enunciado": "Quem se beneficiava, do ponto de vista político e social, da manutenção do mito da democracia racial?", "alternativas": ["A população negra, que ganhava mais representação", "A elite branca, que mantinha privilégios sem precisar justificá-los", "Os povos indígenas, exclusivamente", "Nenhum grupo social específico"], "correta": 1, "comentario": "O mito permitia à elite branca manter privilégios"}],
