questoes:[{"enunciado": "A Declaração Universal dos Direitos Humanos foi adotada pela ONU em:", "alternativas": ["1919", "1945", "1948", "1964"], "correta": 2, "comentario": "A Declaração foi adotada em 10 de dezembro de"}, {"enunciado": "A criação da Declaração Universal dos Direitos Humanos foi motivada principalmente por:", "alternativas": ["O sucesso da Liga das Nações", "Os horrores da Segunda Guerra Mundial, especialmente o Holocausto", "O fim do colonialismo europeu", "A independência de países africanos"], "correta": 1, "comentario": "A Declaração surgiu como resposta direta às"}, {"enunciado": "Sobre a natureza jurídica da Declaração Universal dos Direitos Humanos, é correto afirmar que:", "alternativas": ["É um tratado juridicamente vinculante que permite processar", "Não é juridicamente vinculante por si só, mas serve de base moral e", "Não tem nenhuma relevância jurídica ou política internacional", "Substitui as constituições nacionais dos países-membros"], "correta": 1, "comentario": "A Declaração é uma referência moral e política,"}, {"enunciado": "Uma crítica decolonial relevante à elaboração da Declaração de 1948 é que:", "alternativas": ["Todos os povos do mundo participaram igualmente de sua elaboração", "Povos ainda sob domínio colonial na África e na Ásia não tiveram voz", "A Declaração foi elaborada exclusivamente por países africanos", "Não houve nenhuma limitação na participação de diferentes países"], "correta": 1, "comentario": "Em 1948, grande parte da África e da Ásia ainda"}, {"enunciado": "Apesar de suas limitações históricas, a Declaração Universal dos Direitos Humanos se tornou posteriormente:", "alternativas": ["Um documento sem qualquer uso prático", "Uma ferramenta discursiva usada por movimentos de independência para", "Um instrumento exclusivo das potências coloniais", "Um documento que impediu totalmente os movimentos de independência"], "correta": 1, "comentario": "Movimentos anticoloniais utilizaram os princípios"}],
