atividade:[{"enunciado": "Explique o que foi a Doutrina de Segurança Nacional e como ela justificou as ditaduras latino-americanas."}, {"enunciado": "O que foi a Operação Condor e por que ela demonstra o caráter internacional da repressão política na região?"}, {"enunciado": "Compare o golpe de 1964 no Brasil com o golpe de 1973 no Chile, apontando uma semelhança e uma diferença."}, {"enunciado": "O que foram as Comissões da Verdade e qual sua importância para os países que viveram ditaduras?"}, {"enunciado": "Por que é importante comparar diferentes experiências ditatoriais latino-americanas, em vez de estudá-las isoladamente?"}],
gabarito:[{"resposta": "A Doutrina de Segurança Nacional justificava a repressão interna como defesa contra o 'inimigo interno' comunista, no contexto da Guerra Fria, legitimando a violência de Estado contra opositores políticos.", "comentario": "Valorizar a conexão entre a doutrina e o contexto da Guerra Fria."}, {"resposta": "A Operação Condor foi uma rede de cooperação entre ditaduras latino-americanas para perseguir e assassinar opositores políticos além das fronteiras nacionais, demonstrando que a repressão tinha caráter internacional, coordenado entre diferentes países.", "comentario": "Reforçar que a Operação Condor articulava vários países, não era um fenômeno isolado por nação."}, {"resposta": "Semelhança: ambos foram golpes civis-militares no contexto da Guerra Fria, com apoio ou aval dos EUA. Diferença: o golpe brasileiro teve transição mais lenta e negociada; o chileno foi mais violento e seguido de reformas neoliberais radicais.", "comentario": "Aceitar outras semelhanças/diferenças corretamente fundamentadas."}, {"resposta": "Foram órgãos criados para investigar violações de direitos humanos ocorridas durante as ditaduras. No Brasil, funcionou entre 2012 e 2014. Sua importância está em reconhecer oficialmente essas violações e contribuir para políticas de memória e justiça.", "comentario": "Valorizar a compreensão do papel das Comissões da Verdade na construção da memória histórica."}, {"resposta": "Porque a comparação revela tanto padrões regionais comuns (repressão, censura, apoio dos EUA) quanto particularidades nacionais (duração, intensidade, forma de transição), permitindo uma compreensão mais completa do período.", "comentario": "Valorizar a compreensão do valor metodológico da análise comparativa."}],
questoes:[{"enunciado":"A Doutrina de Segurança Nacional foi usada para:","alternativas":["Promover a democracia na América Latina","Justificar a repressão interna como defesa contra o 'inimigo interno' comunista","Encerrar todas as ditaduras da região","Fortalecer exclusivamente a cultura nacional"],"correta":1,"comentario":"A doutrina legitimava a repressão política em nome do combate ao comunismo."},{"enunciado":"A Operação Condor foi:","alternativas":["Uma missão espacial","Uma rede de cooperação entre ditaduras para perseguir opositores além-fronteiras","Um tratado de paz entre países latino-americanos","Uma organização de defesa dos direitos humanos"],"correta":1,"comentario":"A Operação Condor articulava ditaduras da região na perseguição transnacional de opositores."},{"enunciado":"O golpe de 1973 no Chile teve como particularidade:","alternativas":["Ser negociado pacificamente","Derrubar violentamente um governo eleito (Salvador Allende) e implantar reformas neoliberais radicais","Não ter qualquer apoio militar","Ocorrer sem qualquer repressão política"],"correta":1,"comentario":"O golpe chileno foi violento e seguido de reformas econômicas neoliberais radicais."},{"enunciado":"As Mães e Avós da Praça de Maio são um símbolo de resistência relacionado a:","alternativas":["A ditadura brasileira","A 'Guerra Suja' na Argentina e seus desaparecidos","A ditadura do Paraguai","A Revolução Cubana"],"correta":1,"comentario":"O grupo argentino busca, até hoje, localizar netos e netas apropriados durante a ditadura."},{"enunciado":"Comparar diferentes ditaduras latino-americanas permite:","alternativas":["Ignorar suas diferenças históricas","Identificar semelhanças estruturais e particularidades nacionais","Provar que todas foram idênticas em todos os aspectos","Desconsiderar o contexto da Guerra Fria"],"correta":1,"comentario":"A comparação revela tanto um padrão regional quanto especificidades de cada país."}],
